import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { first } from 'rxjs/operators';
import { Account } from '@app/_models';
import { AccountService, AlertService } from '@app/_services';
import { AlertComponent } from '@app/_components/alert.component';
import { HttpClient } from '@angular/common/http';
import { environment } from '@environments/environment';

@Component({
  templateUrl: 'list.component.html',
  standalone: true,
  imports: [CommonModule, RouterLink, AlertComponent]
})
export class ListComponent implements OnInit {
  accounts: Account[] = [];
  loading = true;
  error: string | null = null;

  constructor(
    private accountService: AccountService, 
    private alertService: AlertService,
    private http: HttpClient
  ) { }

  ngOnInit() {
    console.log('=== LIST COMPONENT INITIALIZED ===');
    this.loadAccounts();
  }

  loadAccounts() {
    this.loading = true;
    this.error = null;
    
    console.log('Calling accountService.getAll()...');
    console.log('API URL:', `${environment.apiUrl}/accounts`);
    
    // Log current user for debugging
    const currentUser = this.accountService.accountValue;
    console.log('Current user:', currentUser);
    console.log('Is user logged in?', !!currentUser);
    console.log('Is user admin?', currentUser?.role === 'Admin');
    
    this.accountService.getAll()
      .pipe(first())
      .subscribe({
        next: (accounts) => {
          console.log('✅ SUCCESS: Accounts loaded successfully');
          console.log('📊 Accounts data:', accounts);
          console.log('📊 Number of accounts:', accounts?.length || 0);
          
          this.accounts = accounts || [];
          this.loading = false;
          
          if (this.accounts.length === 0) {
            console.log('No accounts found');
          }
        },
        error: (error) => {
          console.error('❌ ERROR: Failed to load accounts');
          console.error('Error status:', error.status);
          console.error('Error message:', error.message);
          console.error('Error details:', error.error);
          
          let errorMessage = 'Failed to load accounts. ';
          
          if (error.status === 401) {
            errorMessage += 'You are not authorized. Please log in as admin.';
          } else if (error.status === 403) {
            errorMessage += 'You do not have admin privileges.';
          } else if (error.status === 0) {
            errorMessage += 'Cannot connect to the server. Please check your connection.';
          } else {
            errorMessage += error.error?.message || 'Please try again.';
          }
          
          this.error = errorMessage;
          this.loading = false;
          this.alertService.error(errorMessage);
        }
      });
  }

  deleteAccount(account: Account) {
    if (!confirm(`Are you sure you want to delete ${account.firstName} ${account.lastName}?`)) {
      return;
    }
    
    console.log('Deleting account:', account.id);
    account.isDeleting = true;
    
    this.accountService.delete(account.id)
      .pipe(first())
      .subscribe({
        next: () => {
          console.log('✅ Account deleted successfully:', account.id);
          this.accounts = this.accounts.filter(x => x.id !== account.id);
          this.alertService.success(`${account.firstName} ${account.lastName} was deleted successfully`);
        },
        error: (error) => {
          console.error('❌ Error deleting account:', error);
          account.isDeleting = false;
          
          let errorMessage = 'Failed to delete account. ';
          if (error.status === 401) {
            errorMessage += 'You are not authorized.';
          } else {
            errorMessage += error.error?.message || 'Please try again.';
          }
          
          this.alertService.error(errorMessage);
        }
      });
  }

  // Debug method - manually refresh accounts
  refreshAccounts() {
    console.log('Manual refresh triggered');
    this.loadAccounts();
  }

  // Debug method - check localStorage
  checkLocalStorage() {
    console.log('=== LOCAL STORAGE DEBUG ===');
    const accountsData = localStorage.getItem('angular-auth-boilerplate-accounts');
    if (accountsData) {
      const accounts = JSON.parse(accountsData);
      console.log('Accounts in localStorage:', accounts);
      console.log('Number of accounts:', accounts.length);
    } else {
      console.log('No accounts found in localStorage');
    }
    
    const currentUser = this.accountService.accountValue;
    console.log('Current user from service:', currentUser);
  }

  // Debug method - test direct API call
  testDirectApiCall() {
    console.log('=== TESTING DIRECT API CALL ===');
    const url = `${environment.apiUrl}/accounts`;
    console.log('Making GET request to:', url);
    
    this.http.get(url).subscribe({
      next: (response) => {
        console.log('✅ Direct API response:', response);
        this.alertService.success('API call successful! Check console for details.');
      },
      error: (error) => {
        console.error('❌ Direct API error:', error);
        console.error('Error status:', error.status);
        console.error('Error message:', error.message);
        this.alertService.error(`API call failed: ${error.message}`);
      }
    });
  }

  // Debug method - clear storage and reload
  clearAndReload() {
    if (confirm('This will clear all local data and refresh the page. Continue?')) {
      localStorage.clear();
      console.log('Local storage cleared');
      this.alertService.success('Storage cleared. Page will reload.');
      setTimeout(() => {
        window.location.reload();
      }, 1000);
    }
  }
}
